  function run(){st();var sec=document.createElement("section");sec.id="p0-oracle-crypto-rail";sec.className="section oracle-crypto";sec.innerHTML='<div class="section-head"><div><h2>Oracle 加密证明轨迹</h2><p class="section-sub">'+cfg.note+'</p></div><span class="badge ok">data feed proof</span></div><div class="content oracle-crypto-grid"><div class="oracle-crypto-card"><h3>钱包 / 数据方</h3><ul class="list">'+rows(cfg.wallet)+'</ul></div><div class="oracle-crypto-card"><h3>数据证明</h3><ul class="list">'+rows(cfg.proof)+'</ul></div><div class="oracle-crypto-card"><h3>使用状态</h3><ul class="list">'+rows(cfg.state)+'</ul></div><div class="oracle-crypto-card"><h3>链上 / 触发状态</h3><ul class="list">'+rows(cfg.contract)+'</ul></div></div>';var rail=document.getElementById("p0-oracle-rail");if(rail&&rail.parentNode){rail.parentNode.insertBefore(sec,rail.nextSibling);return}var hero=document.querySelector(".main .hero");if(hero&&hero.parentNode)hero.parentNode.insertBefore(sec,hero.nextSibling);else document.querySelector(".main")?.prepend(sec)}
  if(document.readyState==="loading")document.addEventListener("DOMContentLoaded",run);else run();
